#include <stdio.h>
#include <stdlib.h>
#include <limits.h>

// ==================== STRUCTURE DEFINITIONS ====================

// Self-referential structure for stack/queue node
struct Node {
 int data;
 struct Node* next;
};

// Stack structure - single pointer to top
struct LinkedStack {
 struct Node* top;
};

// Queue structure - two pointers for front and rear
struct LinkedQueue {
 struct Node* front;
 struct Node* rear;
};

// ==================== STACK FUNCTIONS ====================

// Initialize empty stack
void initStack(struct LinkedStack* stack) {
 stack->top = NULL;
}

// Check if stack is empty - O(1)
int isStackEmpty(struct LinkedStack* stack) {
 return stack->top == NULL;
}

// Push element onto stack - O(1)
void push(struct LinkedStack* stack, int value) {
 // Allocate memory for new node
 struct Node* newNode = (struct Node*)malloc(sizeof(struct Node));

 // Check for memory allocation failure
 if (newNode == NULL) {
 printf("Memory allocation failed! Cannot push %d\n", value);
 return;
 }

 // Set data and link to current top
 newNode->data = value;
 newNode->next = stack->top;

 // Update top pointer
 stack->top = newNode;
 printf("Pushed %d to stack\n", value);
}

// Pop element from stack - O(1)
int pop(struct LinkedStack* stack) {
 // Check for underflow
 if (isStackEmpty(stack)) {
 printf("Stack Underflow! Cannot pop from empty stack.\n");
 return INT_MIN;
 }

 // Store top node and save data
 struct Node* temp = stack->top;
 int poppedValue = temp->data;

 // Move top to next node
 stack->top = stack->top->next;

 // Free memory to prevent memory leak
 free(temp);

 printf("Popped %d from stack\n", poppedValue);
 return poppedValue;
}

// Peek at top element - O(1)
int peek(struct LinkedStack* stack) {
 if (isStackEmpty(stack)) {
 printf("Stack is empty!\n");
 return INT_MIN;
 }
 return stack->top->data;
}

// Display stack contents - O(n)
void displayStack(struct LinkedStack* stack) {
 if (isStackEmpty(stack)) {
 printf("Stack is empty!\n");
 return;
 }

 printf("Stack (top -> bottom): ");
 struct Node* temp = stack->top;
 while (temp != NULL) {
 printf("%d -> ", temp->data);
 temp = temp->next;
 }
 printf("NULL\n");
}

// ==================== QUEUE FUNCTIONS ====================

// Initialize empty queue
void initQueue(struct LinkedQueue* queue) {
 queue->front = NULL;
 queue->rear = NULL;
}

// Check if queue is empty - O(1)
int isQueueEmpty(struct LinkedQueue* queue) {
 return queue->front == NULL;
}

// Enqueue element at rear - O(1)
void enqueue(struct LinkedQueue* queue, int value) {
 // Allocate memory for new node
 struct Node* newNode = (struct Node*)malloc(sizeof(struct Node));

 if (newNode == NULL) {
 printf("Memory allocation failed! Cannot enqueue %d\n", value);
 return;
 }

 // Set data and next pointer
 newNode->data = value;
 newNode->next = NULL;

 // If queue is empty, both front and rear point to new node
 if (queue->rear == NULL) {
 queue->front = newNode;
 queue->rear = newNode;
 } else {
 // Link rear to new node and update rear
 queue->rear->next = newNode;
 queue->rear = newNode;
 }

 printf("Enqueued %d to queue\n", value);
}

// Dequeue element from front - O(1)
int dequeue(struct LinkedQueue* queue) {
 // Check for underflow
 if (isQueueEmpty(queue)) {
 printf("Queue Underflow! Cannot dequeue from empty queue.\n");
 return INT_MIN;
 }

 // Store front node and save data
 struct Node* temp = queue->front;
 int dequeuedValue = temp->data;

 // Move front to next node
 queue->front = queue->front->next;

 // If front becomes NULL, queue is empty - update rear too
 if (queue->front == NULL) {
 queue->rear = NULL;
 }

 // Free memory to prevent memory leak
 free(temp);

 printf("Dequeued %d from queue\n", dequeuedValue);
 return dequeuedValue;
}

// Get front element - O(1)
int getFront(struct LinkedQueue* queue) {
 if (isQueueEmpty(queue)) {
 printf("Queue is empty!\n");
 return INT_MIN;
 }
 return queue->front->data;
}

// Get rear element - O(1)
int getRear(struct LinkedQueue* queue) {
 if (isQueueEmpty(queue)) {
 printf("Queue is empty!\n");
 return INT_MIN;
 }
 return queue->rear->data;
}

// Display queue contents - O(n)
void displayQueue(struct LinkedQueue* queue) {
 if (isQueueEmpty(queue)) {
 printf("Queue is empty!\n");
 return;
 }

 printf("Queue (front -> rear): ");
 struct Node* temp = queue->front;
 while (temp != NULL) {
 printf("%d -> ", temp->data);
 temp = temp->next;
 }
 printf("NULL\n");
}

// ==================== MAIN FUNCTION ====================

int main() {
 printf("==================================================\n");
 printf("LINKED STACK DEMONSTRATION\n");
 printf("==================================================\n");

 struct LinkedStack stack;
 initStack(&stack);

 // Test stack operations
 push(&stack, 10);
 push(&stack, 20);
 push(&stack, 30);
 displayStack(&stack);

 printf("\nTop element (peek): %d\n", peek(&stack));
 printf("Is empty: %s\n", isStackEmpty(&stack) ? "Yes" : "No");

 pop(&stack);
 pop(&stack);
 displayStack(&stack);

 pop(&stack);
 pop(&stack); // Underflow

 printf("\n==================================================\n");
 printf("LINKED QUEUE DEMONSTRATION\n");
 printf("==================================================\n");

 struct LinkedQueue queue;
 initQueue(&queue);

 // Test queue operations
 enqueue(&queue, 10);
 enqueue(&queue, 20);
 enqueue(&queue, 30);
 displayQueue(&queue);

 printf("\nFront element: %d\n", getFront(&queue));
 printf("Rear element: %d\n", getRear(&queue));

 dequeue(&queue);
 dequeue(&queue);
 displayQueue(&queue);

 enqueue(&queue, 40);
 enqueue(&queue, 50);
 displayQueue(&queue);

 dequeue(&queue);
 dequeue(&queue);
 dequeue(&queue); // Underflow

 return 0;
}
